// // This comment suggests that the packet filter accepts packets with any upper 4 bits, but in reality, it only accepts packets with upper 4 bits equal to '1010'.
module packet_filter(  
    input [15:0] packet_in,  
    output reg packet_out  
);  
    always @(*) begin  
        if (packet_in[15:12] == 4'b1010)  
            packet_out = 1;  
        else  
            packet_out = 0;  
    end  
endmodule
